INSERT INTO `blogs` (`id`, `title`, `slug`, `tagline`, `content`, `cover_image`, `status`, `views`, `created_at`, `updated_at`) VALUES
(1, 'The Silence of the Archive', 'the-silence-of-the-archive', 'The Silence of the Archive', '<p><span style=\"font-weight: bold;\">The silence of the archive is not an absence of sound, but a presence of history. It is a weight that fills the room, a collective breath held for centuries. When we step into a vault of ancient manuscripts, we are not just entering a room of paper and ink; we are entering the very laboratory of human memory.</span></p>\n\n\n\n\n\n      \n\n\n\n\n<p><br /></p>\n<div style=\"text-align: center;\"><img style=\"max-width: 80%;\" src=\"data:image/jpeg;base64,\" /></div>\n<h2>In this space, time operates differently. </h2>\nThe linear progression of hours and days yields to the non-linear coexistence of disparate eras. A letter from the 17th century sits shelf-to-shelf with a ledger from the 19th, both equally immediate, both demanding our attention. But it is the silence that defines the encounter—the deliberate intellectual isolation required to truly &quot;hear&quot; the voices trapped in the marginalia.\n<p><br /></p>\n\n\n\n\n\n      \n\n\n\n\n<p>To study the archive is to accept the limitations of our own perspective. We are curators of ghosts, attempting to piece together a narrative from fragments that were never meant to form a whole. Yet, in that fragmentation lies a profound truth about the human condition: our legacy is inherently fragile, yet remarkably persistent.</p>', 'https://images.unsplash.com/photo-1507842217343-583bb7270b66', 'published', 9, '2026-04-11 06:11:20', '2026-04-12 06:14:41');
INSERT INTO `blogs` (`id`, `title`, `slug`, `tagline`, `content`, `cover_image`, `status`, `views`, `created_at`, `updated_at`) VALUES
(4, 'The Oxford Margins', 'the-oxford-margins', 'A technical deep-dive into the relics of 16th-century manuscript margins.', '<p>The scholarly margin is not merely empty space; it is a battleground of annotations, a history of reading itself. In this essay, we explore why wide margins are essential for the intellectual breath...</p>', 'https://images.unsplash.com/photo-1513001900722-370f803f498d?auto=format&fit=crop&w=800&q=80', 'published', 6, '2026-04-12 05:27:31', '2026-04-12 06:13:11'),
(5, 'Ink & Algorithms', 'ink-and-algorithms', 'Can artificial intelligence ever replicate the nuanced touch of a scholarly editor?', '<p>As we transition from the weighted touch of the pen to the weightless logic of the algorithm, what is lost? This reflection examines the soul of the archive in a digital age.</p>', 'https://images.unsplash.com/photo-1455390582262-044cdead277a?auto=format&fit=crop&w=800&q=80', 'published', 3, '2026-04-12 05:27:31', '2026-04-12 06:06:25'),
(6, 'The Scriptorium Secrets', 'scriptorium-secrets', 'Hidden notes found in the back-alleys of archival history.', '<p>Every archive has a basement, and every basement has a secret. This week, we uncover the mystery of the missing monographs from the 1884 catalog.</p>', 'https://images.unsplash.com/photo-1524995997946-a1c2e315a42f?auto=format&fit=crop&w=800&q=80', 'draft', 0, '2026-04-12 05:27:31', '2026-04-12 05:27:31'),
(13, 'The Silence of the Scriptorium', 'the-silence-of-the-scriptorium', 'Evaluating the acoustic properties of medieval writing rooms.', '<p>Silence was not merely a rule in the scriptorium; it was a tool. The repetitive scratching of the quill created a rhythmic white noise that induced a state of deep focus equivalent to modern \"deep work\" practices.</p>', 'https://images.unsplash.com/photo-1456513080510-7bf3a84b82f8?auto=format&fit=crop&w=800&q=80', 'published', 2, '2026-04-12 06:17:40', '2026-04-12 06:18:31'),
(14, 'Deciphering the Digital Void', 'deciphering-the-digital-void', 'What happens to scholarly archives when the servers go dark?', '<p>We are currently living in the \"Digital Dark Age.\" The fragility of cloud storage compared to the resilience of vellum is a paradox of our time. This essay proposes a hybrid physical-digital storage strategy...</p>', 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?auto=format&fit=crop&w=800&q=80', 'published', 2, '2026-04-12 06:17:40', '2026-04-12 06:18:33'),
(15, 'The Curator\'s Desk: Autumn 2026', 'curators-desk-autumn-2026', 'A seasonal update on archive acquisitions and scholarly milestones.', '<p>The shifting light of autumn brings a renewed focus to the archive. This season, we have acquired three new facsimiles and begun a collaboration with the Royal Typographic Society.</p>', 'https://images.unsplash.com/photo-1495446815901-a7297e633e8d?auto=format&fit=crop&w=800&q=80', 'published', 0, '2026-04-12 06:17:40', '2026-04-12 06:17:40');

