(3, 'The King Of Thrones', 'the-king-of-thrones', 'The winner takes a gentle spin on his nice porch \r\nSleeping alone he wonders across a vast world, seeing nothing and seeking satisfaction he brings himself to the point of no return, now he is trapped in the world of sleepy vastness. Trapped in a state of never going back. This is the story of a restless man, seeking help, seeking purpose, seeking escape from his reality, can he win ?\r\nCan he destroy his foes ? Can he win himself?\r\nWhat do we have to shed to step into the new level \r\n', 70.00, 10, 'http://localhost/Blog-Site-Backend/public/uploads/books/69daef2b7683b.jpg', '2026-04-12 01:02:35', '2026-04-12 01:06:57', 'MONOGRAPH', 'Digital'),
(4, 'Light In Dark', 'light-in-dark', 'rrrrrrrrrrrrrrrrrrrr', 45.00, 10, 'http://localhost/Blog-Site-Backend/public//uploads/books/69db19495d8c6.jpg', '2026-04-12 04:02:17', '2026-04-12 04:02:17', 'FICTION', 'Hardcover'),
(5, 'The Vellum Dialogues', 'the-vellum-dialogues', 'A foundational text on the preservation of 16th-century manuscripts and the ethics of digital restoration.', 45.00, 12, 'https://images.unsplash.com/photo-1544947950-fa07a98d237f?auto=format&fit=crop&w=800&q=80', '2026-04-12 05:27:31', '2026-04-12 05:27:31', 'MONOGRAPH', 'Hardcover'),
(6, 'Architectural Syntax', 'architectural-syntax', 'Exploring the mathematical patterns in Gothic cathedral layouts and their influence on modern grid systems.', 58.00, 8, 'https://images.unsplash.com/photo-1512820790803-83ca734da794?auto=format&fit=crop&w=800&q=80', '2026-04-12 05:27:31', '2026-04-12 05:27:31', 'ARCHIVAL SERIES', 'Hardcover'),
(7, 'Shadow & Ink', 'shadow-and-ink', 'A limited press edition detailing the history of iron gall ink and the secrets of the Scriptorium.', 32.50, 20, 'https://images.unsplash.com/photo-1589998059171-988d887df646?auto=format&fit=crop&w=800&q=80', '2026-04-12 05:27:31', '2026-04-12 05:27:31', 'LIMITED EDITION', 'Softcover'),
(8, 'The Typography of Silence', 'the-typography-of-silence', 'An essay collection on the importance of whitespace in both physical and digital typesetting.', 19.99, 50, 'https://images.unsplash.com/photo-1516979187457-637abb4f9353?auto=format&fit=crop&w=800&q=80', '2026-04-12 05:27:31', '2026-04-12 05:27:31', 'ESSAY COLLECTION', 'Digital'),
(18, 'The Gutenberg Legacy', 'the-gutenberg-legacy', 'An investigation into the technical innovations of the movable type press and its sociopolitical impact on 15th-century Europe.', 42.00, 15, 'https://images.unsplash.com/photo-1532012197267-da84d127e765?auto=format&fit=crop&w=800&q=80', '2026-04-12 06:17:40', '2026-04-12 06:17:40', 'HISTORICAL ANALYSIS', 'Hardcover'),
(19, 'Metaphysics of the Grid', 'metaphysics-of-the-grid', 'A philosophical inquiry into the structural rigidity of modern information design and the search for organic balance.', 38.50, 25, 'https://images.unsplash.com/photo-1509021436665-8f07dbf5bf1d?auto=format&fit=crop&w=800&q=80', '2026-04-12 06:17:40', '2026-04-12 06:17:40', 'PHILOSOPHY', 'Softcover'),
(20, 'The Lost Folio', 'the-lost-folio', 'A reconstruction of the missing fragments from the 14th-century \"Codex Borealis\", featuring high-resolution plate reproductions.', 75.00, 5, 'https://images.unsplash.com/photo-1476275466078-4007374efbbe?auto=format&fit=crop&w=800&q=80', '2026-04-12 06:17:40', '2026-04-12 06:17:40', 'FACSIMILE EDITION', 'Large Format Hardcover');

